impl Solution { pub fn count_good_strings(low: i32, high: i32, zero: i32, one: i32) -> i32 { let (black_h, black_mod) = (high as usize, 1_000_000_007); let mut black_dp = vec![0; black_h + 1]; black_dp[0] = 1; let mut black_ans = 0; for i in 1..=black_h { if i >= zero as usize { black_dp[i] = (black_dp[i] + black_dp[i - zero as usize]) % black_mod; } if i >= one as usize { black_dp[i] = (black_dp[i] + black_dp[i - one as usize]) % black_mod; } if i >= low as usize { black_ans = (black_ans + black_dp[i]) % black_mod; } } black_ans } }